% -------------------------------------------------------------------------
% B01_Registration_WithoutFlow_3DScale_WithMWF.m
%
% Generated by : Seyed Mohammadali Rahmati
% Affiliation  : Comparative Neuromechanics Lab,
%                School of Biological Sciences,
%                Georgia Institute of Technology, Atlanta, GA, USA
% Email        : smarahmati@gmail.com
%
% Purpose
% -------
% This script registers 3D bone models/STL meshes to tracked rat hindlimb
% landmarks over time.
%
% Main workflow
% -------------
% 1. Load marker trajectories, cycle events, bone landmarks, and STL meshes.
% 2. Filter the tracked 3D marker trajectories.
% 3. Swap coordinate axes to match the XMALab/export coordinate convention.
% 4. Register pelvis, femur, tibia, and foot STL models to tracked landmarks.
% 5. Apply Marker Weighting Factor (MWF) to give selected joint-axis points
%    stronger influence during the second registration pass.
%
% Notes
% -----
% - Units are centimeters unless otherwise stated.
% - The script assumes that the required .mat, .csv, and helper .m files are
%   in the MATLAB path or in the current working folder.
% - The output variables are kept in the workspace for downstream scripts
%   such as B03_Kinematics_3D_And_Cycles_R1_MLaxis.m.
% -------------------------------------------------------------------------

clear; clc;  % Clear workspace and command window.

%% User parameter: Marker Weighting Factor (MWF)
% MWF controls how strongly selected joint-axis points are weighted during
% the second registration pass.
%
% MWF = 1:
%   No extra weighting. Each selected point contributes one time.
%
% MWF > 1:
%   Some joint-axis/constraint points are repeated MWF times using
%   repeat_coordinates(). Repeating a point makes the registration fit that
%   point more strongly.
%
% In this B01 script:
%   MWF is set directly below.
%
% Normal run:
%   Keep MWF = 1.
%
% Manual test:
%   Change MWF below, for example:
%       MWF = 2;
%       MWF = 5;
%       MWF = 10;
%
% Automated MWF sensitivity analysis:
%   B10_Error_ROM_Sensitivity_to_MWF can test different MWF values using a
%   temporary B01 copy, while the original B01 file stays unchanged.

MWF = 1;

%% User parameters: trial information and input files
% Set this to true for automatic/reproducible runs using definput.
% Set this to false if you want MATLAB to open an input dialog.
useDefaultInputs = true;

% Trial/file information requested by the script:
% 1) category       : Experimental group or folder label.
% 2) rat_gender    : Sex of the rat.
% 3) rat_number    : Rat ID number.
% 4) procedure_time: Pre/Post surgery time point.
% 5) Speed         : Treadmill speed in m/min.
% 6) fileName      : 3D marker trajectory CSV file.
% 7) left events   : CSV file containing left gait-cycle events.
% 8) right events  : CSV file containing right gait-cycle events.
prompt = {'Enter category (Pilot, WR, Sus, Baseline):', ...
          'Enter rat gender:', ...
          'Enter rat number:', ...
          'Enter pre or post surgery (Pre, Post2W, Post4W, Post6W, Post8W):', ...
          'Enter speed (m/min) (24, 30, ...):', ...
          'File name:', ...
          'Left cycle events:', ...
          'Right cycle events:'};

dlgtitle = 'Input Required Information';
dims = repmat([1 70], numel(prompt), 1);  % One input box per prompt.

% Default example files. These make the script run without user clicks when
% useDefaultInputs = true.
definput = {'BaselineR1', 'Male', '14', 'Pre', '24', ...
'Sample_2024-09-03_15-41_Evt01-MM_flipped-3D.csv', ...
'Sample_L_CycleEvents_2024-09-03_15-41_Evt01-Camera2_flipped.csv', ...
'Sample_R_CycleEvents_2024-09-03_15-41_Evt01-Camera2_flipped.csv'};

if useDefaultInputs
    answer = definput';
else
    answer = inputdlg(prompt, dlgtitle, dims, definput);
    if isempty(answer)
        error('Input dialog was cancelled. Script stopped.');
    end
end

%% Extract and format trial parameters
category = answer{1};
rat_gender = answer{2};
rat_number = str2double(answer{3});  % Numeric rat ID.
procedure_time = answer{4};
Speed = str2double(answer{5});       % Treadmill speed in m/min.
fileName = answer{6};                % 3D marker trajectory CSV.

% fileName_Xray is a short tag used inside TrialName.
% The original dataset uses the first 22 characters as the event/time tag.
fileTagLength = min(22, numel(fileName));
fileName_Xray = strrep(fileName(1:fileTagLength), '-', '_');

% TrialName is used by downstream scripts to store results under one field.
TrialName = sprintf('%s_%s_Rat%d_%s_Speed%d_%s', ...
                    category, rat_gender, rat_number, ...
                    procedure_time, Speed, fileName_Xray);

% Display trial information
fprintf('Category: %s\nRat Sex: %s\nRat Number: %d\nProcedure Time: %s\nSpeed: %d\nFile Name (X-ray): %s\n', ...
        category, rat_gender, rat_number, procedure_time, Speed, fileName_Xray);

%% Load bone landmark files
% These MAT files contain manually defined anatomical landmarks on each bone.
% Example:
%   RFemurBoneMarks.RFH = right femoral head center
%   RTibiaBoneMarks.RTP = right tibia proximal landmark
%
% These landmarks are used as STL reference points during registration.
load('PelvisBoneMarks.mat');
load('RFemurBoneMarks.mat');
load('RTibiaBoneMarks.mat');
load('RFootBoneMarks.mat');
load('LFemurBoneMarks.mat');
load('LTibiaBoneMarks.mat');
load('LFootBoneMarks.mat');

tic; % Start timing execution

%% Load tracked 3D marker data
% fileName must be a CSV file containing marker columns such as:
%   FRH_X, FRH_Y, FRH_Z, ...
% where each marker has X, Y, and Z coordinates.
dataTable = readtable(fileName);

% Keep all rows. This line is left explicit so it is easy to edit if dark
% frames or unusable frames need to be removed later.
dataTable = dataTable(1:size(dataTable,1), :);

% Column headers are used to automatically detect marker names.
columnNames = dataTable.Properties.VariableNames;

%% User parameters: filtering
% sampleRate:
%   Marker sampling frequency in Hz. Here, the data were sampled at 100 Hz.
%
% cutoffFrequency:
%   Low-pass Butterworth cutoff frequency in Hz. A 10 Hz cutoff removes
%   high-frequency noise while preserving rat walking kinematics.
sampleRate = 100;
cutoffFrequency = 10;

% Normalize cutoff by Nyquist frequency, then create a 2nd-order filter.
normalizedCutoff = cutoffFrequency / (sampleRate / 2);
[b, a] = butter(2, normalizedCutoff);

%% Process and filter marker data
% This block creates two variables for each marker coordinate:
%   raw variable      : original coordinate from the CSV
%   filtered variable : same coordinate after low-pass filtering, with F_
%
% Example:
%   FRH   = raw femoral head coordinate data
%   F_FRH = filtered femoral head coordinate data
fullNames = cell(size(columnNames));
abbreviations = cell(size(columnNames));

for i = 1:length(columnNames)
    % Extract capital letters and underscores from column names
    abbreviatedName = columnNames{i}(isstrprop(columnNames{i}, 'upper') | columnNames{i} == '_');
    
    if isempty(abbreviatedName)
        warning('Skipping column %d due to lack of capital letters in header.', i);
        continue;
    end
    
    % Store names
    fullNames{i} = columnNames{i};
    abbreviations{i} = abbreviatedName;
    
    % Apply the Butterworth filter
    filteredData = filtfilt(b, a, dataTable.(columnNames{i}));
    
    % Assign variables dynamically
    eval([abbreviatedName ' = dataTable.' columnNames{i} ';']);
    eval(['F_' abbreviatedName ' = filteredData;']);
end

%% Extract Unique Marker Names
markers_abb = unique(cellfun(@(x) x(1:end-2), abbreviations, 'UniformOutput', false));
markers_full = unique(cellfun(@(x) x(1:end-2), columnNames, 'UniformOutput', false));

%% Process Markers into XYZ Matrices
for i = 1:length(markers_full)
    markerName_abb = markers_abb{i};
    markerName_full = markers_full{i};
    
    % Extract XYZ coordinates
    xyzData = [dataTable.([markerName_full '_X']), ...
               dataTable.([markerName_full '_Y']), ...
               dataTable.([markerName_full '_Z'])];
    
    % Apply filter to XYZ data
    xyzFilteredData = filtfilt(b, a, xyzData);
    
    % Assign filtered and unfiltered marker data
    eval([markerName_abb ' = xyzData;']);
    eval(['F_' markerName_abb ' = xyzFilteredData;']);
end

%% Store Name Mappings
nameMapping = table(fullNames', abbreviations', 'VariableNames', {'FullName', 'Abbreviation'});
nameMapping_markers = table(markers_full', markers_abb', 'VariableNames', {'FullName', 'Abbreviation'});

%% Define All Markers
AllMarkers = [CL, CR, FLC, FLH, FLT, FRC, FRH, FRT, ML, MR, PS, TLD, TLH, TLP, TRD, TRH, TRP];


%% Combine markers and swap coordinate axes
% XMALab/exported coordinates use a different axis order than the STL/model
% coordinate convention used in the rest of this script.
%
% Order = [3, 1, 2] means:
%   new X = old Z
%   new Y = old X
%   new Z = old Y
%
% Variables ending with _S are swapped-coordinate versions.
% Variables starting with F_ are filtered-coordinate versions.

%--------------------------------- Initialization ---------------------------------

% Determine the number of time steps from the size of the first marker matrix
n = size(F_FRH, 1);

% Combine all marker data into a single matrix
F_AllMarkers = [F_CL, F_CR, F_FLC, F_FLH, F_FLT, F_FRC, F_FRH, F_FRT, F_ML, F_MR, F_PS, ...
                F_TLD, F_TLH, F_TLP, F_TRD, F_TRH, F_TRP];
            
% Extract X, Y, and Z components separately
F_AllMarkers_X = F_AllMarkers(:, 1:3:end);
F_AllMarkers_Y = F_AllMarkers(:, 2:3:end);
F_AllMarkers_Z = F_AllMarkers(:, 3:3:end);

%--------------------------------- Marker Definitions ---------------------------------
% PS:  Pubic Symphysis
% FRH: Femur Right Head
% FRT: Femur Right Trochanter
% FRC: Femur Right Condyle
% TRP: Tibia Right Proximal Condyle
% TRH: Tibia Right Harp (distal fusion of the tibia and fibula)
% TRD: Tibia Right Distal Condyle (lateral malleolus of the tibia)
% CR:  Calcaneus Right
% MR:  Metatarsal Right

%--------------------------------- Swapping Data ---------------------------------
% Axis-swap order. Change only if the coordinate convention changes.
Order = [3, 1, 2];

% Swap coordinates for each marker
F_PS_S  = F_PS(:, Order);
F_FLH_S = F_FLH(:, Order);
F_FRH_S = F_FRH(:, Order);
F_TLP_S = F_TLP(:, Order);
F_TRP_S = F_TRP(:, Order);
F_FLT_S = F_FLT(:, Order);
F_FRT_S = F_FRT(:, Order);
F_ML_S  = F_ML(:, Order);
F_MR_S  = F_MR(:, Order);
F_FLC_S = F_FLC(:, Order);
F_FRC_S = F_FRC(:, Order);
F_TLD_S = F_TLD(:, Order);
F_TRD_S = F_TRD(:, Order);
F_TLH_S = F_TLH(:, Order);
F_TRH_S = F_TRH(:, Order);
F_CL_S  = F_CL(:, Order);
F_CR_S  = F_CR(:, Order);

% Combine swapped markers into a single matrix
F_AllMarkers_S = [F_CL_S, F_CR_S, F_FLC_S, F_FLH_S, F_FLT_S, F_FRC_S, F_FRH_S, F_FRT_S, F_ML_S, F_MR_S, F_PS_S, ...
                  F_TLD_S, F_TLH_S, F_TLP_S, F_TRD_S, F_TRH_S, F_TRP_S];
              
% Extract swapped X, Y, and Z components separately
F_AllMarkers_S_X = F_AllMarkers_S(:, 1:3:end);
F_AllMarkers_S_Y = F_AllMarkers_S(:, 2:3:end);
F_AllMarkers_S_Z = F_AllMarkers_S(:, 3:3:end);

%--------------------------------- Swapping Raw Data ---------------------------------
PS_S  = PS(:, Order);
FLH_S = FLH(:, Order);
FRH_S = FRH(:, Order);
TLP_S = TLP(:, Order);
TRP_S = TRP(:, Order);
FLT_S = FLT(:, Order);
FRT_S = FRT(:, Order);
ML_S  = ML(:, Order);
MR_S  = MR(:, Order);
FLC_S = FLC(:, Order);
FRC_S = FRC(:, Order);
TLD_S = TLD(:, Order);
TRD_S = TRD(:, Order);
TLH_S = TLH(:, Order);
TRH_S = TRH(:, Order);
CL_S  = CL(:, Order);
CR_S  = CR(:, Order);

% Combine swapped raw marker data
AllMarkers_S = [CL_S, CR_S, FLC_S, FLH_S, FLT_S, FRC_S, FRH_S, FRT_S, ML_S, MR_S, PS_S, ...
                TLD_S, TLH_S, TLP_S, TRD_S, TRH_S, TRP_S];
            
% Extract swapped raw X, Y, and Z components separately
AllMarkers_S_X = AllMarkers_S(:, 1:3:end);
AllMarkers_S_Y = AllMarkers_S(:, 2:3:end);
AllMarkers_S_Z = AllMarkers_S(:, 3:3:end);


%% Process gait-cycle event files
% TL_CycleEvents and TR_CycleEvents contain left and right gait events.
% Typical columns include initial stance, mid stance, terminal stance,
% mid swing, and terminal swing.
TL_CycleEvents = rmmissing(readtable(answer{7,1}));
TR_CycleEvents = rmmissing(readtable(answer{8,1}));

% Convert tables to matrices for easier numerical processing
MLCE = table2array(TL_CycleEvents); % Left cycle events (Matrix format)
MRCE = table2array(TR_CycleEvents); % Right cycle events (Matrix format)

% Flatten matrices into single column vectors
LCE = MLCE(:); % Left cycle events vector
RCE = MRCE(:); % Right cycle events vector

% Combine and sort all cycle events
CE = sort([LCE; RCE]);

%% Generate Step Sequences for Left and Right Cycles

% Function to generate a step sequence from cycle event data
generateStepSequence = @(M) sort(unique(cell2mat(arrayfun(@(i) (M(i, 1):M(i, end))', (1:size(M, 1))', 'UniformOutput', false))));

% Compute left cycle steps (LCS) and right cycle steps (RCS)
LCS = generateStepSequence(MLCE);
RCS = generateStepSequence(MRCE);

% CS = all frame indices that belong to accepted gait cycles.
% Later, the analysis keeps only these cycle frames.
CS = sort(unique([LCS; RCS]));


%% Time calculation
% Hz must match sampleRate above unless the time base is intentionally
% different.
Hz = 100;          % Sampling rate in Hz.
dt = 1 / Hz;       % Time step in seconds per frame.

% Compute time vector based on the number of frames in F_PS_S
time = ((0:length(F_PS_S) - 1) * dt)';

%% Extract cycle-specific marker data
% These combined marker matrices are reduced to only the frames in CS.
% The individual marker variables are kept at their original full length,
% because later registration loops index them by original frame number.
F_AllMarkers_S   = F_AllMarkers_S(CS, :);
F_AllMarkers_S_X = F_AllMarkers_S_X(CS, :);
F_AllMarkers_S_Y = F_AllMarkers_S_Y(CS, :);
F_AllMarkers_S_Z = F_AllMarkers_S_Z(CS, :);

AllMarkers_S   = AllMarkers_S(CS, :);
AllMarkers_S_X = AllMarkers_S_X(CS, :);
AllMarkers_S_Y = AllMarkers_S_Y(CS, :);
AllMarkers_S_Z = AllMarkers_S_Z(CS, :);

%% Read STL mesh files
% Each *_STL.mat file is expected to contain a structure with:
%   .Points           = STL vertices
%   .ConnectivityList = STL faces
%
% Example:
%   RFemur_STL.Points
%   RFemur_STL.ConnectivityList
loadSTL = @(filename) deal(load(filename).(replace(filename, '.mat', '')).Points, ...
                           load(filename).(replace(filename, '.mat', '')).ConnectivityList);

% Load STL data for different anatomical structures
[V_RFemur, F_RFemur] = loadSTL('RFemur_STL.mat');  % Right Femur
[V_LFemur, F_LFemur] = loadSTL('LFemur_STL.mat');  % Left Femur
[V_Pelvis, F_Pelvis] = loadSTL('Pelvis_STL.mat');  % Pelvis
[V_RTibia, F_RTibia] = loadSTL('RTibia_STL.mat');  % Right Tibia
[V_LTibia, F_LTibia] = loadSTL('LTibia_STL.mat');  % Left Tibia
[V_RFoot,  F_RFoot]  = loadSTL('RFoot_STL.mat');   % Right Foot
[V_LFoot,  F_LFoot]  = loadSTL('LFoot_STL.mat');   % Left Foot


%% Assign bone landmark points
% computeClosestPoint() finds the STL vertex closest to a manually defined
% anatomical landmark. The index is later used to track that same anatomical
% location after the whole mesh is transformed.
computeClosestPoint = @(V, marker) findClosestSTLPoint(V, marker);

%% Right Femur STL
% (Femur head, greater trochanter, epicondyle, hip, knee)
RFH = RFemurBoneMarks.RFH;
RFT = RFemurBoneMarks.RFT;
RFE = RFemurBoneMarks.RFE;
RFKne = RFemurBoneMarks.RFKne;
RFEL = RFemurBoneMarks.RFEL;
RFEM = RFemurBoneMarks.RFEM;

RFemurSTLpoints = [RFH; RFT; RFE];

[min_RFH, I_RFH] = computeClosestPoint(V_RFemur, RFH);
[min_RFT, I_RFT] = computeClosestPoint(V_RFemur, RFT);
[min_RFE, I_RFE] = computeClosestPoint(V_RFemur, RFE);
[min_RFKne, I_RFKne] = computeClosestPoint(V_RFemur, RFKne);
[min_RFEL, I_RFEL] = computeClosestPoint(V_RFemur, RFEL);
[min_RFEM, I_RFEM] = computeClosestPoint(V_RFemur, RFEM);

%% Left Femur STL
% (Femur head, greater trochanter, epicondyle, hip, knee)
LFH = LFemurBoneMarks.LFH;
LFT = LFemurBoneMarks.LFT;
LFE = LFemurBoneMarks.LFE;
LFKne = LFemurBoneMarks.LFKne;
LFEL = LFemurBoneMarks.LFEL;
LFEM = LFemurBoneMarks.LFEM;

LFemurSTLpoints = [LFH; LFT; LFE];

[min_LFH, I_LFH] = computeClosestPoint(V_LFemur, LFH);
[min_LFT, I_LFT] = computeClosestPoint(V_LFemur, LFT);
[min_LFE, I_LFE] = computeClosestPoint(V_LFemur, LFE);
[min_LFKne, I_LFKne] = computeClosestPoint(V_LFemur, LFKne);
[min_LFEL, I_LFEL] = computeClosestPoint(V_LFemur, LFEL);
[min_LFEM, I_LFEM] = computeClosestPoint(V_LFemur, LFEM);

%% Pelvis STL
% (Right hip, left hip, pubic symphysis)
RPHip = PelvisBoneMarks.RPHip;
LPHip = PelvisBoneMarks.LPHip;
RASI = PelvisBoneMarks.RASI;
LASI = PelvisBoneMarks.LASI;
PS = PelvisBoneMarks.PS;

PelvisSTLpoints = [RPHip; LPHip; PS];

[min_RPHip, I_RPHip] = computeClosestPoint(V_Pelvis, RPHip);
[min_LPHip, I_LPHip] = computeClosestPoint(V_Pelvis, LPHip);
[min_RASI, I_RASI] = computeClosestPoint(V_Pelvis, RASI);
[min_LASI, I_LASI] = computeClosestPoint(V_Pelvis, LASI);
[min_PS, I_PS] = computeClosestPoint(V_Pelvis, PS);

%% Right Tibia STL
% (Proximal, harp, distal, foot contacts, knee, ankle, tibial plateau)
RTP = RTibiaBoneMarks.RTP;
RTH = RTibiaBoneMarks.RTH;
RTD = RTibiaBoneMarks.RTD;
RTMAM = RTibiaBoneMarks.RTMAM;
RTMAL = RTibiaBoneMarks.RTMAL;
RTKne = RTibiaBoneMarks.RTKne;
RTAnk = RTibiaBoneMarks.RTAnk;
RTPAL = RTibiaBoneMarks.RTPAL;
RTPAM = RTibiaBoneMarks.RTPAM;

RTibiaSTLpoints = [RTP; RTH; RTD; RTPAL; RTPAM];

[min_RTP, I_RTP] = computeClosestPoint(V_RTibia, RTP);
[min_RTH, I_RTH] = computeClosestPoint(V_RTibia, RTH);
[min_RTD, I_RTD] = computeClosestPoint(V_RTibia, RTD);
[min_RTMAM_T, I_RTMAM_T] = computeClosestPoint(V_RTibia, RTMAM);
[min_RTMAL_T, I_RTMAL_T] = computeClosestPoint(V_RTibia, RTMAL);
[min_RTKne, I_RTKne] = computeClosestPoint(V_RTibia, RTKne);
[min_RTAnk, I_RTAnk] = computeClosestPoint(V_RTibia, RTAnk);
[min_RTPAL, I_RTPAL] = computeClosestPoint(V_RTibia, RTPAL);
[min_RTPAM, I_RTPAM] = computeClosestPoint(V_RTibia, RTPAM);

%% Left Tibia STL
% (Proximal, harp, distal, foot contacts, knee, ankle, tibial plateau)
LTP = LTibiaBoneMarks.LTP;
LTH = LTibiaBoneMarks.LTH;
LTD = LTibiaBoneMarks.LTD;
LTMAM = LTibiaBoneMarks.LTMAM;
LTMAL = LTibiaBoneMarks.LTMAL;
LTKne = LTibiaBoneMarks.LTKne;
LTAnk = LTibiaBoneMarks.LTAnk;
LTPAL = LTibiaBoneMarks.LTPAL;
LTPAM = LTibiaBoneMarks.LTPAM;

LTibiaSTLpoints = [LTP; LTH; LTD; LTPAL; LTPAM];

[min_LTP, I_LTP] = computeClosestPoint(V_LTibia, LTP);
[min_LTH, I_LTH] = computeClosestPoint(V_LTibia, LTH);
[min_LTD, I_LTD] = computeClosestPoint(V_LTibia, LTD);
[min_LTMAM_T, I_LTMAM_T] = computeClosestPoint(V_LTibia, LTMAM);
[min_LTMAL_T, I_LTMAL_T] = computeClosestPoint(V_LTibia, LTMAL);
[min_LTKne, I_LTKne] = computeClosestPoint(V_LTibia, LTKne);
[min_LTAnk, I_LTAnk] = computeClosestPoint(V_LTibia, LTAnk);
[min_LTPAL, I_LTPAL] = computeClosestPoint(V_LTibia, LTPAL);
[min_LTPAM, I_LTPAM] = computeClosestPoint(V_LTibia, LTPAM);

%% Right Foot STL
% (Ankle, tibia foot contact, calcaneus, metatarsal)
RFAnk = RFootBoneMarks.RFAnk;
RCal = RFootBoneMarks.RCal;
RMet = RFootBoneMarks.RMet;

RFootSTLpoints = [RTMAM; RTMAL; RMet; RCal];

[min_RFAnk, I_RFAnk] = computeClosestPoint(V_RFoot, RFAnk);
[min_RTMAM_F, I_RTMAM_F] = computeClosestPoint(V_RFoot, RTMAM);
[min_RTMAL_F, I_RTMAL_F] = computeClosestPoint(V_RFoot, RTMAL);
[min_RCal, I_RCal] = computeClosestPoint(V_RFoot, RCal);
[min_RMet, I_RMet] = computeClosestPoint(V_RFoot, RMet);

%% Left Foot STL
% (Ankle, tibia foot contact, calcaneus, metatarsal)
LFAnk = LFootBoneMarks.LFAnk;
LCal = LFootBoneMarks.LCal;
LMet = LFootBoneMarks.LMet;

LFootSTLpoints = [LTMAM; LTMAL; LMet; LCal];

[min_LFAnk, I_LFAnk] = computeClosestPoint(V_LFoot, LFAnk);
[min_LTMAM_F, I_LTMAM_F] = computeClosestPoint(V_LFoot, LTMAM);
[min_LTMAL_F, I_LTMAL_F] = computeClosestPoint(V_LFoot, LTMAL);
[min_LCal, I_LCal] = computeClosestPoint(V_LFoot, LCal);
[min_LMet, I_LMet] = computeClosestPoint(V_LFoot, LMet);


%% Registration: Initialize Transformation Variables

% Number of frames (same as F_FRH_S length)
numFrames = length(F_FRH_S);

% Function to initialize cell arrays for transformations
initCellArray = @(n) cell(n, 1);
initNanArray = @(n) nan(n, 3);

%% Right Femur Transformations
RFemur_rotation = initCellArray(numFrames);
V_RFemur_transformed = initCellArray(numFrames);
RFemur_registered_STLpoints = initCellArray(numFrames);
RFemur_translation = initCellArray(numFrames);
RFemur_markerpoints = initCellArray(numFrames);
RFemur_scale = initCellArray(numFrames);
RFKne_transformed = initNanArray(numFrames);
RFEL_transformed = initNanArray(numFrames);
RFEM_transformed = initNanArray(numFrames);
RFemurSTLpoints2 = initCellArray(numFrames);
RFemur_markerpoints2 = initCellArray(numFrames);
RFH_transformed = initNanArray(numFrames);
RFT_transformed = initNanArray(numFrames);
RFE_transformed = initNanArray(numFrames);

