%% Step 1: Pelvis Registration and Transformation

% Number of frames
numFrames = length(time);

% Compute mean STL points for normalization
meanPelvisSTLpoints = mean(PelvisSTLpoints);

% scaleMatrixArray stores the frame-by-frame 3D scale matrices.
% The average scale is later used so the bone mesh does not change size
% abruptly from frame to frame.
scaleMatrixArray = nan(3,3,numFrames);

% Perform 3D registration for the pelvis at each time step
for i = 1:numFrames
    % Define STL reference points for pelvis
    STLpoints = PelvisSTLpoints;

    % Reference marker points for pelvis (Femur Right Head, Femur Left Head, Pubic Symphysis)
    Pelvis_markerpoints{i,1} = [F_FRH_S(i,:); F_FLH_S(i,:); F_PS_S(i,:)];

    % Check if current frame index is in CS (cycle steps)
    if ismember(i, CS)
        % Registration with scale adjustment
        [Pelvis_rotation{i,1}, Pelvis_translation{i,1}, Pelvis_scale{i,1}] = ...
            rigid_transform_3D_MA(Pelvis_markerpoints{i,1}, STLpoints);
        scaleMatrixArray(:,:,i) = Pelvis_scale{i,1};
    else
        % Registration without scale adjustment
        [Pelvis_rotation{i,1}, Pelvis_translation{i,1}] = ...
            rigid_transform_3D_MA(Pelvis_markerpoints{i,1}, STLpoints);
    end
end

% Compute mean scale matrix from all transformations
scale = mean(scaleMatrixArray, 3, 'omitnan');

% Apply transformations to each frame
for i = 1:numFrames
    % Extract transformation parameters
    rotation = Pelvis_rotation{i,1};
    translation = Pelvis_translation{i,1};

    % Transform STL vertices
    V_transformed = (V_Pelvis - meanPelvisSTLpoints) * scale' * rotation' + translation;
    V_Pelvis_transformed{i,1} = V_transformed;

    % Transform registered STL points
    Pelvis_registered_STLpoints{i,1} = (PelvisSTLpoints - meanPelvisSTLpoints) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    RPHip_transformed(i,:) = V_transformed(I_RPHip,:);
    LPHip_transformed(i,:) = V_transformed(I_LPHip,:);
    RASI_transformed(i,:) = V_transformed(I_RASI,:);
    LASI_transformed(i,:) = V_transformed(I_LASI,:);
    PS_transformed(i,:) = V_transformed(I_PS,:);
end



%% Step 2: Femur Registration and Transformation

