%% Step 5: Weight joint-axis points for femur registration
% This second pass improves joint-axis consistency.
%
% repeat_counts = [MWF, MWF, 1, 1, 1] means:
%   - The first two points are joint-axis points and are repeated MWF times.
%   - The remaining anatomical landmarks are used once.
%
% Larger MWF gives joint-axis points stronger influence during registration.
% MWF = 1 gives all points equal influence.

% Number of frames
numFrames = length(F_FRH_S);

for i = 1:numFrames
    %---------------------------------- 3D Points Registration for Right Femur -------------------------------------
    RSTLpoints = [RFEM_transformed(i,:); RFEL_transformed(i,:); ...
                  RFH_transformed(i,:); RFT_transformed(i,:); RFE_transformed(i,:)];

    % Define the repeat counts for each point
    repeat_counts = [MWF, MWF, 1, 1, 1]; % Repeat the first and second points MWF times, others once

    % Repeat the marker points based on the specified counts
    RFemur_markerpoints{i,1} = repeat_coordinates([RTPAM_transformed(i,:); RTPAL_transformed(i,:); ...
                                                   F_FRH_S(i,:); F_FRT_S(i,:); F_FRC_S(i,:)], repeat_counts);

    % Repeat the corresponding STL points
    RSTLpoints_repeated = repeat_coordinates(RSTLpoints, repeat_counts);

    % Perform the rigid transformation
    [RFemur_rotation{i,1}, RFemur_translation{i,1}] = ...
        rigid_transform_3D_MA(RFemur_markerpoints{i,1}, RSTLpoints_repeated);

    %---------------------------------- 3D Points Registration for Left Femur -------------------------------------
    LSTLpoints = [LFEM_transformed(i,:); LFEL_transformed(i,:); ...
                  LFH_transformed(i,:); LFT_transformed(i,:); LFE_transformed(i,:)];

    % Repeat the marker points based on the specified counts
    LFemur_markerpoints{i,1} = repeat_coordinates([LTPAM_transformed(i,:); LTPAL_transformed(i,:); ...
                                                   F_FLH_S(i,:); F_FLT_S(i,:); F_FLC_S(i,:)], repeat_counts);

    % Repeat the corresponding STL points
    LSTLpoints_repeated = repeat_coordinates(LSTLpoints, repeat_counts);

    % Perform the rigid transformation
    [LFemur_rotation{i,1}, LFemur_translation{i,1}] = ...
        rigid_transform_3D_MA(LFemur_markerpoints{i,1}, LSTLpoints_repeated);

    %---------------------------------- STL Registration for Right Femur -------------------------------------
    rotation = RFemur_rotation{i,1};
    translation = RFemur_translation{i,1};

    scale = eye(3); % Identity matrix for scale

    % Transform STL vertices
    V_transformed = (V_RFemur_transformed{i,:} - mean(RSTLpoints_repeated)) * scale' * rotation' + translation;
    V_RFemur_transformed{i,1} = V_transformed;

    % Transform registered STL points
    RFemur_registered_STLpoints{i,1} = (RFemur_registered_STLpoints{i,1} - mean(RSTLpoints_repeated)) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    RFH_transformed(i,:) = V_transformed(I_RFH,:);
    RFT_transformed(i,:) = V_transformed(I_RFT,:);
    RFE_transformed(i,:) = V_transformed(I_RFE,:);
    RFKne_transformed(i,:) = V_transformed(I_RFKne,:);
    RFEL_transformed(i,:) = V_transformed(I_RFEL,:);
    RFEM_transformed(i,:) = V_transformed(I_RFEM,:);

    %---------------------------------- STL Registration for Left Femur -------------------------------------
    rotation = LFemur_rotation{i,1};
    translation = LFemur_translation{i,1};

    % Transform STL vertices
    V_transformed = (V_LFemur_transformed{i,:} - mean(LSTLpoints_repeated)) * scale' * rotation' + translation;
    V_LFemur_transformed{i,1} = V_transformed;

    % Transform registered STL points
    LFemur_registered_STLpoints{i,1} = (LFemur_registered_STLpoints{i,1} - mean(LFemurSTLpoints)) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    LFH_transformed(i,:) = V_transformed(I_LFH,:);
    LFT_transformed(i,:) = V_transformed(I_LFT,:);
    LFE_transformed(i,:) = V_transformed(I_LFE,:);
    LFKne_transformed(i,:) = V_transformed(I_LFKne,:);
    LFEL_transformed(i,:) = V_transformed(I_LFEL,:);
    LFEM_transformed(i,:) = V_transformed(I_LFEM,:);
end


%% Step 6: Weight joint-axis points for tibia registration
% Same logic as Step 5. The first two repeated points represent the knee
% joint-axis relationship between femur and tibia.

