    RTibia_markerpoints{i,1} = repeat_coordinates([RFEM_transformed(i,:); RFEL_transformed(i,:); 
                                                   F_TRP_S(i,:); F_TRH_S(i,:); F_TRD_S(i,:)], repeat_counts);

