    % Repeat the corresponding STL points
    LSTLpoints_repeated = repeat_coordinates(LSTLpoints, repeat_counts);

    % Perform the rigid transformation
    [LTibia_rotation{i,1}, LTibia_translation{i,1}] = ...
        rigid_transform_3D_MA(LTibia_markerpoints{i,1}, LSTLpoints_repeated);

    %---------------------------------- STL Registration for Right Tibia -------------------------------------
    rotation = RTibia_rotation{i,1};
    translation = RTibia_translation{i,1};
    scale = eye(3);

    % Transform STL vertices
    V_transformed = (V_RTibia_transformed{i,:} - mean(RSTLpoints_repeated)) * scale' * rotation' + translation;
    V_RTibia_transformed{i,1} = V_transformed;

    % Transform registered STL points
    RTibia_registered_STLpoints{i,1} = (RTibia_registered_STLpoints{i,1} - mean(RSTLpoints_repeated)) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    RTP_transformed(i,:) = V_transformed(I_RTP,:);
    RTH_transformed(i,:) = V_transformed(I_RTH,:);
    RTD_transformed(i,:) = V_transformed(I_RTD,:);
    RTMAM_T_transformed(i,:) = V_transformed(I_RTMAM_T,:);
    RTMAL_T_transformed(i,:) = V_transformed(I_RTMAL_T,:);
    RTKne_transformed(i,:) = V_transformed(I_RTKne,:);
    RTAnk_transformed(i,:) = V_transformed(I_RTAnk,:);
    RTPAL_transformed(i,:) = V_transformed(I_RTPAL,:);
    RTPAM_transformed(i,:) = V_transformed(I_RTPAM,:);

    %---------------------------------- STL Registration for Left Tibia -------------------------------------
    rotation = LTibia_rotation{i,1};
    translation = LTibia_translation{i,1};

    % Transform STL vertices
    V_transformed = (V_LTibia_transformed{i,:} - mean(LSTLpoints_repeated)) * scale' * rotation' + translation;
    V_LTibia_transformed{i,1} = V_transformed;

    % Transform registered STL points
    LTibia_registered_STLpoints{i,1} = (LTibia_registered_STLpoints{i,1} - mean(LTibiaSTLpoints)) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    LTP_transformed(i,:) = V_transformed(I_LTP,:);
    LTH_transformed(i,:) = V_transformed(I_LTH,:);
    LTD_transformed(i,:) = V_transformed(I_LTD,:);
    LTMAM_T_transformed(i,:) = V_transformed(I_LTMAM_T,:);
    LTMAL_T_transformed(i,:) = V_transformed(I_LTMAL_T,:);
    LTKne_transformed(i,:) = V_transformed(I_LTKne,:);
    LTAnk_transformed(i,:) = V_transformed(I_LTAnk,:);
    LTPAL_transformed(i,:) = V_transformed(I_LTPAL,:);
    LTPAM_transformed(i,:) = V_transformed(I_LTPAM,:);
end


%% Step 7: Weight joint-axis points for foot registration
% The first two repeated points represent the ankle/tibia-foot contact axis.
% repeat_counts = [MWF, MWF, 1, 1] weights those two axis points.

for i = 1:numFrames
    %---------------------------------- 3D Points Registration for Right Foot -------------------------------------
    RSTLpoints = [RTMAM_F_transformed(i,:); RTMAL_F_transformed(i,:); RMet_transformed(i,:); RCal_transformed(i,:)];

    % Define the repeat counts for weighting
    repeat_counts = [MWF, MWF, 1, 1];

    % Repeat the marker points based on the specified counts
    RFoot_markerpoints{i,1} = repeat_coordinates([RTMAM_T_transformed(i,:); RTMAL_T_transformed(i,:); 
                                                  F_MR_S(i,:); F_CR_S(i,:)], repeat_counts);

    % Repeat the corresponding STL points
    RSTLpoints_repeated = repeat_coordinates(RSTLpoints, repeat_counts);

    % Perform the rigid transformation
    [RFoot_rotation{i,1}, RFoot_translation{i,1}] = ...
        rigid_transform_3D_MA(RFoot_markerpoints{i,1}, RSTLpoints_repeated);

    %---------------------------------- 3D Points Registration for Left Foot -------------------------------------
    LSTLpoints = [LTMAM_F_transformed(i,:); LTMAL_F_transformed(i,:); LMet_transformed(i,:); LCal_transformed(i,:)];

    % Repeat the marker points based on the specified counts
    LFoot_markerpoints{i,1} = repeat_coordinates([LTMAM_T_transformed(i,:); LTMAL_T_transformed(i,:); 
                                                  F_ML_S(i,:); F_CL_S(i,:)], repeat_counts);

    % Repeat the corresponding STL points
    LSTLpoints_repeated = repeat_coordinates(LSTLpoints, repeat_counts);

    % Perform the rigid transformation
    [LFoot_rotation{i,1}, LFoot_translation{i,1}] = ...
        rigid_transform_3D_MA(LFoot_markerpoints{i,1}, LSTLpoints_repeated);

    %---------------------------------- STL Registration for Right Foot -------------------------------------
    rotation = RFoot_rotation{i,1};
    translation = RFoot_translation{i,1};
    scale = eye(3);

    % Transform STL vertices
    V_transformed = (V_RFoot_transformed{i,:} - mean(RSTLpoints_repeated)) * scale' * rotation' + translation;
    V_RFoot_transformed{i,1} = V_transformed;

    % Transform registered STL points
    RFoot_registered_STLpoints{i,1} = (RFoot_registered_STLpoints{i,1} - mean(RSTLpoints_repeated)) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    RTMAM_F_transformed(i,:) = V_transformed(I_RTMAM_F,:);
    RTMAL_F_transformed(i,:) = V_transformed(I_RTMAL_F,:);
    RFAnk_transformed(i,:) = V_transformed(I_RFAnk,:);
    RCal_transformed(i,:) = V_transformed(I_RCal,:);
    RMet_transformed(i,:) = V_transformed(I_RMet,:);

    %---------------------------------- STL Registration for Left Foot -------------------------------------
    rotation = LFoot_rotation{i,1};
    translation = LFoot_translation{i,1};

    % Transform STL vertices
    V_transformed = (V_LFoot_transformed{i,:} - mean(LSTLpoints_repeated)) * scale' * rotation' + translation;
    V_LFoot_transformed{i,1} = V_transformed;

    % Transform registered STL points
    LFoot_registered_STLpoints{i,1} = (LFoot_registered_STLpoints{i,1} - mean(LFootSTLpoints)) * scale' * rotation' + translation;

    % Update transformed anatomical landmarks
    LTMAM_F_transformed(i,:) = V_transformed(I_LTMAM_F,:);
    LTMAL_F_transformed(i,:) = V_transformed(I_LTMAL_F,:);
    LFAnk_transformed(i,:) = V_transformed(I_LFAnk,:);
    LCal_transformed(i,:) = V_transformed(I_LCal,:);
    LMet_transformed(i,:) = V_transformed(I_LMet,:);
end


elapsedTime = toc; % End timing and compute elapsed time
fprintf('Elapsed Time: %f seconds\n', elapsedTime);


%% Local helper function
function [minDistance, closestIndex] = findClosestSTLPoint(vertices, marker)
%FINDCLOSESTSTLPOINT Find the closest STL vertex to one anatomical point.
%
% Inputs
% ------
% vertices : Nx3 matrix
%   STL mesh vertices.
%
% marker : 1x3 vector
%   Anatomical landmark coordinate.
%
% Outputs
% -------
% minDistance : scalar
%   Distance from marker to the closest STL vertex.
%
% closestIndex : scalar
%   Row index of the closest STL vertex in vertices.

    distances = sqrt(sum((vertices - marker).^2, 2));
    [minDistance, closestIndex] = min(distances);
end
